import torch


def statistics(values):
    center = values.mean(dim=0, keepdim=True)
    scale = values.std(dim=0, keepdim=True, unbiased=False)
    return center, scale.clamp_min(torch.finfo(values.dtype).eps)


def standardize(values, center, scale):
    return (values - center) / scale

