"""Candidate-owned model architecture."""

import torch


class Model(torch.nn.Module):
    def __init__(self, input_size, output_size, device, dtype):
        super().__init__()
        options = {"device": device, "dtype": dtype}
        self.network = torch.nn.Sequential(
            torch.nn.Linear(input_size, 32, **options),
            torch.nn.SiLU(),
            torch.nn.Linear(32, 32, **options),
            torch.nn.SiLU(),
            torch.nn.Linear(32, output_size, **options),
        )

    def forward(self, inputs):
        return self.network(inputs)
